import { isEmpty, isNil } from 'lodash-es';

import type { HeaderData, TooltipValue } from '../../../types.js';

type DefinedTooltipData = string | number | Date;

export const isDateRange = (data: HeaderData): data is [Date, Date] => {
  return (
    data instanceof Array &&
    data.length === 2 &&
    data.every((item) => item instanceof Date)
  );
};

export const isNumericRange = (data: HeaderData): data is [number, number] => {
  return (
    data instanceof Array &&
    data.length === 2 &&
    data.every((item) => typeof item === 'number')
  );
};

export const isStringRange = (data: HeaderData): data is [string, string] => {
  return (
    data instanceof Array &&
    data.length === 2 &&
    data.every((item) => typeof item === 'string')
  );
};

export const isNonEmptyRange = (
  data: HeaderData,
): data is [DefinedTooltipData, DefinedTooltipData] => {
  return (
    data instanceof Array &&
    data.length === 2 &&
    data.every((item) => !isNil(item))
  );
};

export const isFromTo = (
  data: HeaderData,
): data is [TooltipValue, TooltipValue] => {
  return (
    data instanceof Array &&
    data.length === 2 &&
    data.every((item) => !isNil(item))
  );
};
export const isSingleValue = (
  data: HeaderData,
): data is TooltipValue | [TooltipValue] =>
  (data instanceof Array && data.length === 1 && !isNil(data[0])) ||
  (!(data instanceof Array) && !isNil(data));

export const isHeaderEmpty = (
  header1: HeaderData | undefined,
  header2: HeaderData | undefined,
  subheader: HeaderData | undefined,
) =>
  (isNil(header1) || isEmpty(header1)) &&
  (isNil(header2) || isEmpty(header2)) &&
  (isNil(subheader) || isEmpty(subheader));
